def usr_whatsapp_message_interaction(doc):

    def is_system(doc):
        if doc.modified_by == frappe.get_doc('System User').get('username'):
            return True
        else:
            return False

    if is_system(doc):
        return

    if doc.reference_doctype == 'Issue' and doc.reference_name and doc.type == 'Outgoing':
        issue = frappe.get_doc('Issue', doc.reference_name)
        if not issue.first_responded_on:
            time_now = frappe.utils.get_datetime(frappe.utils.now())
            creation_time = frappe.utils.get_datetime(issue.creation)
            first_response_time = (time_now - creation_time).total_seconds()
            issue.first_response_time = f"{first_response_time:.2f}"  # Format to float with 2 decimal places
            issue.first_responded_on = frappe.utils.now()
            issue.custom_first_response_by = doc.modified_by
            issue.save(ignore_permissions=True)
            return

usr_whatsapp_message_interaction(doc)

def usr_comm_message_interaction(doc):
    def is_user():
        if not doc.modified_by == frappe.get_doc('System User').get('username'):
            return True
        else:
            return False

    if not is_user():
        return
    
    if doc.reference_doctype == 'Issue' and doc.reference_name:
        issue = frappe.get_doc('Issue', doc.reference_name)
        if issue.first_responded_on: # frappe sets first_responded_on automatically
            issue.custom_first_response_by = doc.modified_by
            issue.save(ignore_permissions=True)
            return
        
    
    
usr_comm_message_interaction(doc)

customer = frappe.get_doc("Customer", doc.name)


if customer.customer_primary_contact:
    contact = frappe.get_doc("Contact", customer.customer_primary_contact)
    # Check if the contact is already linked to this customer
    existing_link = frappe.get_all("Dynamic Link", filters={
        'link_doctype': 'Customer',
        'link_name': customer.name,
        'parent': contact.name  # Parent is the Contact document
    })

    if existing_link:
        # The contact is already linked to this customer
        frappe.msgprint(f"Contact '{contact.name}' is already linked to the customer '{customer.name}'.")
    else:
        # Link the contact to the customer
        contact.append('links', {
            'link_doctype': 'Customer',
            'link_name': customer.name
        })
        contact.save()
        frappe.msgprint(f"Contact '{contact.name}' has been linked to the customer '{customer.name}'.")
else:
    frappe.msgprint("No Primary Contact was given")
